"use client"

import * as React from "react"

import { cn } from "@/registry/bases/base/lib/utils"

type StepperContextValue = {
  activeStep: string
  orientation: "horizontal" | "vertical"
  onStepChange: (value: string) => void
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

function Stepper({
  activeStep,
  onStepChange,
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  activeStep: string
  onStepChange: (value: string) => void
  orientation?: "horizontal" | "vertical"
}) {
  return (
    <StepperContext.Provider value={{ activeStep, orientation, onStepChange }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "cn-stepper group/stepper flex",
          orientation === "horizontal"
            ? "flex-col gap-4"
            : "flex-row gap-4",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

function StepperList({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-list"
      role="tablist"
      aria-orientation={orientation}
      className={cn(
        "cn-stepper-list flex",
        orientation === "horizontal"
          ? "flex-row items-center"
          : "flex-col",
        className
      )}
      {...props}
    />
  )
}

function StepperItem({
  value,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  value: string
}) {
  const { activeStep } = useStepper()
  const isActive = activeStep === value

  return (
    <div
      data-slot="stepper-item"
      data-state={isActive ? "active" : "inactive"}
      className={cn(
        "cn-stepper-item group/stepper-item flex items-center",
        className
      )}
      {...props}
    >
      {children}
    </div>
  )
}

function StepperTrigger({
  value,
  className,
  ...props
}: React.ComponentProps<"button"> & {
  value: string
}) {
  const { activeStep, onStepChange } = useStepper()
  const isActive = activeStep === value

  return (
    <button
      data-slot="stepper-trigger"
      type="button"
      role="tab"
      aria-selected={isActive}
      data-state={isActive ? "active" : "inactive"}
      className={cn(
        "cn-stepper-trigger flex items-center gap-3 rounded-md px-3 py-2 text-left text-sm font-medium outline-none transition-colors",
        "focus-visible:ring-ring/50 focus-visible:ring-[3px]",
        "disabled:pointer-events-none disabled:opacity-50",
        isActive
          ? "text-foreground"
          : "text-muted-foreground hover:text-foreground/80",
        className
      )}
      onClick={() => onStepChange(value)}
      {...props}
    />
  )
}

function StepperIndicator({
  className,
  ...props
}: React.ComponentProps<"span">) {
  return (
    <span
      data-slot="stepper-indicator"
      className={cn(
        "cn-stepper-indicator bg-muted text-muted-foreground group-data-[state=active]/stepper-item:bg-primary group-data-[state=active]/stepper-item:text-primary-foreground flex size-8 shrink-0 items-center justify-center rounded-full text-xs font-medium transition-colors",
        className
      )}
      {...props}
    />
  )
}

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"span">) {
  return (
    <span
      data-slot="stepper-title"
      className={cn("cn-stepper-title text-sm font-medium", className)}
      {...props}
    />
  )
}

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"span">) {
  return (
    <span
      data-slot="stepper-description"
      className={cn(
        "cn-stepper-description text-muted-foreground text-xs",
        className
      )}
      {...props}
    />
  )
}

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-separator"
      role="separator"
      aria-orientation={orientation}
      className={cn(
        "cn-stepper-separator bg-muted",
        orientation === "horizontal"
          ? "mx-2 h-px flex-1"
          : "my-2 ml-[1.1rem] h-8 w-px",
        className
      )}
      {...props}
    />
  )
}

function StepperContent({
  value,
  className,
  ...props
}: React.ComponentProps<"div"> & {
  value: string
}) {
  const { activeStep } = useStepper()

  if (activeStep !== value) {
    return null
  }

  return (
    <div
      data-slot="stepper-content"
      role="tabpanel"
      data-state="active"
      className={cn(
        "cn-stepper-content mt-2",
        className
      )}
      {...props}
    />
  )
}

export {
  Stepper,
  StepperList,
  StepperItem,
  StepperTrigger,
  StepperIndicator,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
  useStepper,
}

